function inferirTiposDado(source) {
  const texto = [
    source.name || "",
    source.desc || "",
    source.meta || "",
    (source.topics || []).join(" ")
  ]
    .join(" ")
    .toLowerCase();

  const tipos = new Set();

  const temGeorreferenciado =
    /shapefile|shape|geojson|geopackage|gpkg|kml|kmz|wms|wfs|wmts|tile|raster|sat[eé]lite|imagem|imagens|lidar|dem|batimetria|ortofoto|ortoimagem|webmap|mapa|mapas|cartografia|geoespacial|georreferenciado|camadas|vetor|vetoriais|malha|setores censit[aá]rios|grade espacial|endere[cç]os|top[oô]nimos|topografia|hidrogr[aá]fia|bacias|eleva[cç][aã]o|altimetria/.test(texto);

  const temTabular =
    /csv|xls|xlsx|planilha|tabela|tabelas|estat[ií]stic|indicadores|s[eé]ries|s[ée]rie hist[oó]rica|cat[aá]logo|catálogo|dados abertos|portal de dados|api|download em lote|reposit[oó]rio|dataset|datasets|base de dados|popula[cç][aã]o|densidade|monitoramento|qualidade de [aá]gua|temperatura|precipita[cç][aã]o|radia[cç][aã]o|socioecon[oô]mic/.test(texto);

  const temNaoEstruturado =
    /pdf|relat[oó]rio|relat[oó]rios|publica[cç][aã]o|publica[cç][oõ]es|nota t[eé]cnica|documento|documentos|artigo|artigos|painel|pain[eé]is|visualiza[cç][aã]o|visualizador|explorer|portal|cat[aá]logo|catálogo|web/.test(texto);

  if (temGeorreferenciado) tipos.add("georreferenciado");
  if (temTabular) tipos.add("tabular");
  if (temNaoEstruturado) tipos.add("nao_estruturado");

  if (tipos.size === 0) {
    if (source.cat === "sat" || source.cat === "dem" || source.cat === "ocean") {
      tipos.add("georreferenciado");
    } else if (source.cat === "climate" || source.cat === "urban" || source.cat === "all") {
      tipos.add("tabular");
    } else {
      tipos.add("georreferenciado");
    }
  }

  return Array.from(tipos);
}

