function setPageTab(tab, btn, shouldScroll = true) {
  document.querySelectorAll('.page-tab').forEach(button => button.classList.remove('active'));
  if (btn) btn.classList.add('active');

  document.querySelectorAll('.content-pane').forEach(pane => pane.classList.add('hidden-pane'));
  document.querySelectorAll('.pane-' + tab).forEach(pane => pane.classList.remove('hidden-pane'));

  if (tab === 'mapa') {
    if (typeof initMap === 'function') initMap();
    if (typeof refreshSourceMap === 'function') refreshSourceMap();
  }

  if (!shouldScroll) return;

  if (tab === 'fontes') {
    document.getElementById('controles')?.scrollIntoView({ behavior: 'smooth', block: 'start' });
  } else if (tab === 'objetivos') {
    document.getElementById('sobre-catalogo')?.scrollIntoView({ behavior: 'smooth', block: 'start' });
  } else if (tab === 'iso') {
    document.getElementById('iso-categorias')?.scrollIntoView({ behavior: 'smooth', block: 'start' });
  } else if (tab === 'curadoria') {
    document.getElementById('sobre-curadoria')?.scrollIntoView({ behavior: 'smooth', block: 'start' });
  } else if (tab === 'mapa') {
    document.getElementById('mapa')?.scrollIntoView({ behavior: 'smooth', block: 'start' });
  } else if (tab === 'manuais') {
    document.getElementById('manuais')?.scrollIntoView({ behavior: 'smooth', block: 'start' });
  } else if (tab === 'cursos') {
    document.getElementById('cursos')?.scrollIntoView({ behavior: 'smooth', block: 'start' });
  }
}

function applyScopePreset(value) {
  setPageTab('fontes', document.querySelector('.page-tab[data-tab="fontes"]') || null, false);
  setEscalaFilter(value);
  document.getElementById('controles')?.scrollIntoView({ behavior: 'smooth', block: 'start' });
}





