// Base de dados do agente — preenchida após renderSections()
let fontesDatabase = [];

function carregarFontesDatabase() {
  fontesDatabase = [];
  document.querySelectorAll('.card').forEach(card => {
    fontesDatabase.push({
      id: Number(card.getAttribute('data-id') || 0),
      titulo: card.getAttribute('data-name') || '',
      url: card.getAttribute('data-url') || '',
      descricao: card.getAttribute('data-desc') || '',
      topicos: (card.getAttribute('data-topics') || '').split(' ').filter(Boolean),
      escala: card.getAttribute('data-escala') || '',
      tema: card.getAttribute('data-tema-principal') || '',
      pais: card.getAttribute('data-pais') || '',
      estrutura: card.getAttribute('data-estrutura') || '',
      acesso: card.getAttribute('data-acesso') || ''
    });
  });
  console.log('🗄️ Agente: ' + fontesDatabase.length + ' fontes indexadas');
}

function abrirAgente() {
  var chatDiv = document.getElementById('agente-chat');
  chatDiv.style.display = 'flex';
  document.getElementById('agent-input').focus();
}

// Abrir/Fechar agente — inicializa após DOM ready
document.addEventListener('DOMContentLoaded', function() {
  var toggle = document.getElementById('agente-toggle');
  if (toggle) {
    toggle.addEventListener('click', function() {
      var chatDiv = document.getElementById('agente-chat');
      if (chatDiv.style.display === 'none' || !chatDiv.style.display) {
        abrirAgente();
      } else {
        chatDiv.style.display = 'none';
      }
    });
  }
});

function fecharAgente() {
  document.getElementById('agente-chat').style.display = 'none';
}

function buscaInteligente(query) {
  const termos = expandQueryTerms(query);
  const resultados = fontesDatabase.map(fonte => {
    const textoCompleto = [
      fonte.titulo,
      fonte.descricao,
      fonte.topicos.join(' '),
      fonte.tema,
      fonte.escala,
      fonte.pais,
      fonte.estrutura,
      fonte.acesso
    ].join(' ').toLowerCase();

    let score = 0;
    termos.forEach(termo => {
      if (textoCompleto.includes(termo)) score += 2;
      if (fonte.titulo.toLowerCase().includes(termo)) score += 3;
      if (fonte.tema.toLowerCase().includes(termo)) score += 2;
      if (fonte.topicos.join(' ').toLowerCase().includes(termo)) score += 2;
    });

    return { ...fonte, score };
  }).filter(item => item.score > 0)
    .sort((a, b) => b.score - a.score)
    .slice(0, 6);

  return resultados;
}

function formatarResultado(fonte) {
  return `
    <div class="agent-result-card">
      <strong>📍 ${escapeAgente(fonte.titulo)}</strong>
      <p>${escapeAgente(fonte.descricao)}</p>
      <div class="agent-result-actions">
        <button class="agent-mini-btn" onclick="aplicarFiltroAgente(${fonte.id})">Destacar</button>
        <button class="agent-mini-btn" onclick="openDetails(${fonte.id})">Detalhes</button>
        <button class="agent-mini-btn" onclick="window.open('${fonte.url}', '_blank')">Abrir</button>
      </div>
    </div>`;
}

function sugerirAcao(pergunta) {
  const q = normalizarTexto(pergunta);
  const sugestoes = [];

  if (/biodiversidade|fauna|flora|especies/.test(q)) sugestoes.push(['Aplicar Biodiversidade', () => setTheme('biodiversidade', null)]);
  if (/clima|chuva|temperatura|precipitacao/.test(q)) sugestoes.push(['Aplicar Clima', () => setTheme('clima', null)]);
  if (/relevo|dem|mde|elevacao/.test(q)) sugestoes.push(['Aplicar Relevo', () => setTheme('relevo', null)]);
  if (/urbano|cidade|setor censitario|populacao/.test(q)) sugestoes.push(['Aplicar Urbano', () => setTheme('urbano', null)]);
  if (/brasil|brasileiro|brasileira/.test(q)) sugestoes.push(['Filtrar Brasil', () => setEscalaFilter('brasil')]);
  if (/global|mundo|mundial/.test(q)) sugestoes.push(['Filtrar Global', () => setEscalaFilter('global')]);
  if (/raster|imagem|satelite|satélite|dem/.test(q)) sugestoes.push(['Estrutura Geoespacial', () => { estruturaFilter = 'geoespacial'; filterCards(); }]);
  if (/vetor|vetorial|limites|malha/.test(q)) sugestoes.push(['Estrutura Vetorial', () => { estruturaFilter = 'vetorial'; filterCards(); }]);
  return sugestoes;
}

function aplicarFiltroAgente(id) {
  const item = getSourceById(id);
  if (!item) return;
  activeTheme = item.topics?.[0] || null;
  setEscalaFilter(item.escala || 'all');
  setTemaPrincipalFilter(item.tema_principal || 'all');
  paisFilter = item.pais_ref || 'all';
  estruturaFilter = item.estrutura_tecnica || 'all';
  document.getElementById('searchInput').value = item.name;
  filterCards();
  fecharAgente();
  document.getElementById('controles')?.scrollIntoView({ behavior: 'smooth', block: 'start' });
}

function renderSugestoesAgente(sugestoes) {
  if (!sugestoes.length) return '';
  const html = sugestoes.map((item, index) => `<button class="agent-suggestion-btn" onclick="executarSugestaoAgente(${index})">${escapeAgente(item[0])}</button>`).join('');
  window.__agentSuggestions = sugestoes;
  return `<div class="agent-suggestion-grid">${html}</div>`;
}

function executarSugestaoAgente(index) {
  const sugestoes = window.__agentSuggestions || [];
  if (sugestoes[index]) {
    sugestoes[index][1]();
    filterCards();
  }
}

function enviarPerguntaAgente() {
  const input = document.getElementById('agent-input');
  const pergunta = input.value.trim();
  if (!pergunta) return;

  const messagesDiv = document.getElementById('chat-messages');
  messagesDiv.innerHTML += `
    <div style="align-self:flex-end;max-width:80%;padding:10px 14px;background:linear-gradient(135deg,#19c2ff,#3b2ccf);color:white;border-radius:12px 12px 4px 12px;font-size:13px;line-height:1.5;">
      ${escapeAgente(pergunta)}
    </div>`;
  input.value = '';
  messagesDiv.scrollTop = messagesDiv.scrollHeight;

  const resultadosLocais = buscaInteligente(pergunta);
  const sugestoes = sugerirAcao(pergunta);

  let intro = 'Encontrei algumas fontes que fazem mais sentido para essa busca.';
  if (!resultadosLocais.length) {
    intro = 'Não achei uma correspondência forte pelo texto exato. Mesmo assim, deixei sugestões de filtro para você afunilar a busca.';
  }

  const resultadosHtml = resultadosLocais.length
    ? resultadosLocais.map(f => formatarResultado(f)).join('')
    : '<div class="helper-note">Tente usar termos como biodiversidade, cartografia, raster, vetorial, urbano, clima ou o nome do país.</div>';

  messagesDiv.innerHTML += `
    <div style="padding:14px;background:white;border-radius:12px;border-left:4px solid #3b2ccf;font-size:13px;color:#333;line-height:1.65;box-shadow:0 2px 8px rgba(31,41,55,0.05);">
      <strong style="color:#3b2ccf;display:block;margin-bottom:6px;">Leitura do agente</strong>
      <div>${escapeAgente(intro)}</div>
      ${renderSugestoesAgente(sugestoes)}
      <div style="margin-top:10px;display:flex;flex-direction:column;gap:6px;">${resultadosHtml}</div>
    </div>`;

  messagesDiv.scrollTop = messagesDiv.scrollHeight;
}

function escapeAgente(str) {
  return String(str || '')
    .replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')
    .replace(/"/g,'&quot;');
}


